var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>ARC-KS1</color>\\n번화가 멀티플렉스, ■년 전.","JPN":"<color=#ffd34c>ARC-KS1</color>\\n繁華街のマルチプレックス、■年前。","ENG":"<color=#ffd34c>ARC-KS1</color>\\nDowntown Multiplex. ■ years ago.","TWN":"<color=#ffd34c>ARC-KS1</color>\\n鬧區大型商場，■年前"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"제 아버지는 거의 완벽한 존재입니다.","JPN":"私の父はほぼ完璧な存在です。","ENG":"My Father is a near-perfect being.","TWN":"我的爸爸幾乎是零缺點般的完美。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_QM","text":{"KOREA":"하지만 그 말을 역으로 생각하면, 결국 완벽하지 못한 존재라는 뜻이죠.","JPN":"ですがその言葉を逆にとれば、結局は完ぺきではない存在という意味です。","ENG":"However, if phrased differently, it implies that he is not perfect.","TWN":"但反過來說，也無法達到完美的意思吧。"},"stage":{"bg":"MS_1001","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_QM","text":{"KOREA":"단 한 걸음.","JPN":"たった一歩。","ENG":"Always one step short.","TWN":"一步。"},"stage":{"bg":"MS_1001","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_QM","text":{"KOREA":"그 한 걸음이 부족했기에 아버지는 항상 모든 것을 잃어 왔습니다.","JPN":"その一歩が足りないせいで、父は常にすべてを失ってきました。","ENG":"He lost everything because he could not take that one extra step.","TWN":"就因為差那一步，爸爸總是在失去。"},"stage":{"bg":"MS_1001","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_QM","text":{"KOREA":"그래서 저는 아버지가 그 부족한 한 걸음을 내디딜 수 있도록 도와드리고 있습니다.","JPN":"ですから私は父がその足りない一歩を踏み出すことができるようにお手伝いしています。","ENG":"That is why I am assisting Father in taking the one step he is lacking.","TWN":"因此我總是在幫助爸爸可以達到那一步。"},"stage":{"bg":"MS_1001","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MAN_NPC_ALPHA_NULL","text":{"KOREA":"아…… 네. 장한 따님, 아니 아드님이시군요.","JPN":"あ……はい。健気な娘さん、いや、息子さんですね。","ENG":"Oh... He's lucky to have you as his daugh– Oh, I mean, son.","TWN":"喔……好棒的女兒…不對，是好棒的兒子喔～"},"stage":{"bg":"MS_1001","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MAN_NPC_ALPHA_NULL","text":{"KOREA":"그런데 그런 이야기를 왜 갑자기 저에게 와서 하시는 겁니까?","JPN":"ところで、どうしてそんな話をいきなり私のところに来てするんですか？","ENG":"But why are you suddenly telling me this?","TWN":"不過你為何要突然跑來跟我說這些呢？"},"stage":{"bg":"MS_1001","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_QM","text":{"KOREA":"간단합니다. 당신에게는 제 이야기를 들을 자격이 있기 때문이죠.","JPN":"理由は簡単です。あなたには私の話を聞く資格があるからです。","ENG":"Simple. Because you are worthy of hearing it.","TWN":"理由很簡單，因為你有資格聽我說這些。"},"stage":{"bg":"MS_1001","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MAN_NPC_ALPHA_NULL","text":{"KOREA":"……저기, 학생. 포교인지 뭔지 모르겠지만, 아무튼 저는 관심없어요.","JPN":"……あのね。布教だか何だかわかりませんけど、とにかく私は興味ありませんから。","ENG":"...Look, kid. Whatever you have to say, I'm not interested. All right?","TWN":"……我說，這位同學，我不管你是要跟我傳教還是幹嘛，總之我沒興趣。"},"stage":{"bg":"MS_1001","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_QM","text":{"KOREA":"그렇겠죠. 당신에겐 이런 뜬구름 잡는 이야기보다 더 소중한 가족이 있으니까요.","JPN":"そうでしょうね。あなたにはこのようなつかみどころのない話よりももっと大切な家族がいるのですから。","ENG":"Just as I expected. You put your family first before some absurd story, do you not?","TWN":"那是當然，對你來說，你的家人比這些摸不著頭緒的話來得更重要吧。"},"stage":{"bg":"MS_1001","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_QM","text":{"KOREA":"마침 가족 분들이 오실 시간이군요.","JPN":"ちょうどご家族の皆さんが来る時間ですね。","ENG":"I see your family is right on time to see you.","TWN":"正好你的家人就快來囉。"},"stage":{"bg":"MS_1002","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_QM","text":{"KOREA":"강력계라는 직업 때문에 성격이 거치신 건 이해하지만, 따님들 앞에서 아내 분께 너무 화내지 마세요.","JPN":"刑事という職業柄、性格が荒いのは理解できますが、娘さんたちの前で奥さんを叱るのは控えた方がいいですよ。","ENG":"I understand that you get hot-headed due to your job in charge of violent crimes. But please do not lash out on your wife in front of your daughters.","TWN":"我明白你的職業是刑警，性格上比較粗枝大葉一點，但也別在女兒們面前對太太那麼兇。"},"stage":{"bg":"MS_1002","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MAN_NPC_ALPHA_NULL","text":{"KOREA":"잠깐, 보자보자 하니까 당신 대체 뭐야? 우리 딸들은 어떻게 알고!","JPN":"あんた、黙って聞いてればいったい何者なんだ？　うちの娘たちをなんで知ってる！","ENG":"Wait a minute...! Who the hell are you, huh?! How do you know about my daughters?!","TWN":"喂，你不要太過分喔，你到底是誰？怎麼會認識我女兒！"},"stage":{"bg":"MS_1002","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"WOMAN_EP9HALF_NULL_NULL","text":{"KOREA":"어머? 여보, 밖에 나와 있었어요?","JPN":"あら？　あなた、外に出てたの？","ENG":"Hmm? Honey, what are you doing out in the cold?","TWN":"嗯？老公，你怎麼會出來？"},"stage":{"bg":"MS_1002","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"OSISTER_EP9HALF_NULL_NULL","text":{"KOREA":"차에 있지. 애들 보라고 만든 영화인데 엄청 길더라.","JPN":"車で待ってたらよかったのに。子ども向けの映画なのにやたら長くてさ。","ENG":"Why didn't you stay in the car? This film was far too long, even for a kid's movie.","TWN":"怎麼不待在車裡，說是給兒童看的電影，片長還真長。"},"stage":{"bg":"MS_1002","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YSISTER_EP9HALF_NULL_NULL","text":{"KOREA":"아빠! 이것 봐, 새로 나온 브레멘 전대 인형이다?","JPN":"お父さん！　これ見て、新しいブレーメン戦隊の人形だよ！","ENG":"Daddy! Look at this! It's the new Town Soldiers of Bremen doll!","TWN":"爸爸！你看，是布萊梅戰隊新出的娃娃欸！"},"stage":{"bg":"MS_1002","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MAN_NPC_ALPHA_NULL","text":{"KOREA":"여보, 당신 또 유미가 조른다고 덥석 사 준 거야?","JPN":"おい、またユミがねだるからって買ってやったのか？","ENG":"Honey, you didn't buy Yumi this because she kept pestering you, did you?","TWN":"老婆，你又亂買東西給悠美嗎？"},"stage":{"bg":"MS_1002","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MAN_NPC_ALPHA_NULL","text":{"KOREA":"그러면 애 버릇……. 나빠진다고…….","JPN":"ユミが……行儀悪く……","ENG":"You keep that up and she'll... get spoiled...","TWN":"你這樣會寵壞……孩子……"},"stage":{"bg":"MS_1002","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"WOMAN_EP9HALF_NULL_NULL","text":{"KOREA":"여보? 왜 그래요?","JPN":"あなた？　どうしたの？","ENG":"Honey? What's wrong?","TWN":"老公？你怎麼啦？"},"stage":{"bg":"MS_1002","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MAN_NPC_ALPHA_NULL","text":{"KOREA":"당신, 어떻게 안 거야……?","JPN":"あんた、どうやって知ったんだ……？","ENG":"How... How did you know I was gonna...?","TWN":"你怎麼會知道……？"},"stage":{"bg":"MS_1001","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_QM","text":{"KOREA":"가족 분들과 모쪼록 좋은 시간 보내시길 바랍니다.","JPN":"ご家族と楽しい時間をお過ごしください。","ENG":"I hope you have a great time with your family.","TWN":"祝你和家人們有個愉快的時間，"},"stage":{"bg":"MS_1001","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_QM","text":{"KOREA":"그럼, 저는 이만.","JPN":"それでは、私はこれで。","ENG":"Goodbye.","TWN":"我先告辭。"},"stage":{"bg":"MS_1001","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"OSISTER_EP9HALF_NULL_NULL","text":{"KOREA":"방금 그 사람 누구에요, 아빠? 직장 동료예요?","JPN":"お父さん、今の人は誰？　職場の人？","ENG":"Who was that, Daddy? A friend of yours from work?","TWN":"剛那個人是誰？是爸爸的同事嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MAN_NPC_ALPHA_NULL","text":{"KOREA":"아니……. 유리 넌 신경 쓰지 않아도 돼.","JPN":"いや……ユリ、お前は気にしなくていい。","ENG":"No... Don't worry about him, Yuri.","TWN":"不是……不用管他，悠麗。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MAN_NPC_ALPHA_NULL","text":{"KOREA":"자, 자. 어서 차 타러 가자. 날씨도 춥다.","JPN":"さあ、さあ。早く車に乗ろう。寒いな。","ENG":"C'mon, let's all get in the car. It's freezing out here!","TWN":"走吧走吧，我們回車上去吧，天氣好冷喔～"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"네 부탁대로 큰 딸이 마실 음료에 약을 타 뒀어, 시솝.","JPN":"あなたの頼みどおり、長女の飲み物に薬を盛っておいたわ、シソップ。","ENG":"I slipped the drug into the eldest daughter's drink like you asked, Sysop.","TWN":" 錫索普，我已經照你的吩咐，將藥混到大女兒要喝的飲料裡。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"오늘 하루만큼은 신체 능력도, 생존 본능도 베테랑 특수부대원이 놀랄 만큼 강해질 거야.","JPN":"今日一日だけは身体能力も生存本能も、ベテランの特殊部隊員に劣らないくらい強くなるはずよ。","ENG":"At least for today, her physical abilities and survival instincts will be stronger and sharper than those of a special forces veteran.","TWN":"今天她的體能和生存本能，都將提升到如特戰部隊那般驚人。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"신경이 좀 예민해지는 부작용은 있지만…… 갑작스러운 천재지변에도 충분히 살아남겠지.","JPN":"ちょっと神経質になる副作用はあるでしょうけど……急な天災地変にも十分生き残るわ。","ENG":"She might get a little sensitive, but... she'll be able to survive anything that comes her way.","TWN":"雖然副作用是會變得有點敏感……但面對突然其來的災害，要活下來不是問題。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"고맙군. 마담. 항상 도움을 받고 있어.","JPN":"ありがたい、マダム。いつも世話をかけるね。","ENG":"Thank you, madam. I'm in your debt.","TWN":"謝謝夫人，常受你幫忙呢。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"오늘은 분위기가 평소와 다른걸. 기특한 소리도 다 하고.","JPN":"今日はいつもと雰囲気が違うのね。しおらしいこと言って。","ENG":"You seem different today, hmm? Being thankful now, are you?","TWN":"你今天感覺和平時不太一樣呢，竟然說這種話。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"그래서 누구니, 저 남자는?","JPN":"それで、あの男は誰なの？","ENG":"So? Who is that man anyway?","TWN":"所以呢？他是誰？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"어디에서나 볼 수 있는 평범한 남자라네.","JPN":"どこにでもいる普通の男さ。","ENG":"Just an ordinary man, living an ordinary life.","TWN":"就只是一個隨處可見的平凡男性。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"자신의 아내와 함께 오늘 밤 자정에 사망할 예정이야. 내 계획에 상당히 중요한 분기점이지.","JPN":"妻と今夜0時に死亡する予定だ。私の計画でかなり重要な分岐点になる。","ENG":"He is also destined to die alongside his wife tonight. A rather important turning point in my plans.","TWN":"他今天午夜將和太太一起死去，是我的計畫中相當重要的交叉點。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"그래? 아까 하는 얘길 들어 보니 경찰이라던데, 평의회 활동의 걸림돌이라도 되니?","JPN":"そう？　さっきの話を聞いていると警察らしいけど、評議会の活動に邪魔なのかしら？","ENG":"Is that so? I heard you say he's a police officer. Does he impede the Council's work?","TWN":"是嗎？從你剛說的話聽起來，他好像是警察？他會變成評議會行動的絆腳石嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"저들의 죽음은 우연이란 기재가 지독하게 작용한 결과일 뿐이야.","JPN":"彼らの死は偶然というメカニズムが極限まで作用した結果に過ぎない。","ENG":"Their deaths are the result of the devastating effects which people refer to as coincidence.","TWN":"他們的死亡不過是必然的結果。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"내가 한 일이라고는…… 우연이 모여 만들어낸 결과값을 계산했는데도 개입하지 않은 것뿐이지.","JPN":"私がやったことといえば……偶然が折り重なって作り出した結果値を計算で知っていたにもかかわらず、介入しなかったというだけだ。","ENG":"All I did was... calculate the outcomes of the coincidences, but never intervene.","TWN":"而我所做的……就是有計算出偶遇後發生的結果值，但沒有介入而已。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"아버지라면 마지막까지 망설인 끝에 개입하고 말았겠지만.","JPN":"父なら最後まで迷ったあげく介入してしまっただろうが。","ENG":"Father, on the other hand, would have intervened after hesitating until the end.","TWN":"不過要是爸爸，他一定猶豫過後還是會選擇介入。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"그럼 왜 저 남자에게 말을 건 거니? 괜한 소리를 했다가 일이 틀어지면 어쩌려고?","JPN":"じゃあ、どうしてあの男に話しかけたのかしら？　余計なことを言って、予定通りにならなかったらどうするつもり？","ENG":"Then why did you go talk to him? What if you said something that throws everything off course?","TWN":"那你為何要主動找他搭話？萬一因為你說的話，把事情搞砸的話怎麼辦？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"아버지에게 배웠으니까.","JPN":"父に教わったからな。","ENG":"It is what I learned from Father.","TWN":"這是我向爸爸學的。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"누군가를 구하지 않기로 했다면, 기억해야 하는 법이라고.","JPN":"誰かを救わないと決めたのなら、覚えておくべきだと。","ENG":"If you are not going to save someone, the least you can do is remember who they were.","TWN":"若是下定決心對某人見死不救，起碼要記住他的樣子。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"……풋내기, 너 생각보다 다정한 남자네.","JPN":"……坊や、あなた思ったより優しい男ね。","ENG":"Oh my... You're more considerate than I had thought.","TWN":"……小鬼，沒想到你是個重感情的男人。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"다정해? 내가 말인가?","JPN":"優しい？　私が？","ENG":"Considerate? Me?","TWN":"重感情？你說我嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"왜? 내가 못할 말이라도 했니?","JPN":"何？　変なことでも言った？","ENG":"Why? Did I say something that's not true?","TWN":"我有哪裡說錯嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"……아니. 하지만 고려해 본 적 없는 평판이군.","JPN":"……いや。考えてみたこともなかったな。","ENG":"No... But it is something that I have never considered.","TWN":"……沒有，只是我沒想過會聽到這種評價。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"내 행동은 계산에서 도출된 결과에 불과해. 처음부터 정이라는 걸 모르도록 만들어졌으니까.","JPN":"私の行動は計算から導き出された結果に過ぎない。最初から情というものを解さないように作られたのだから。","ENG":"My actions are simply the outcome of my calculations. The concept of \\"affection\\" was never taken into account when I was created.","TWN":"畢竟我的一舉一動不過就是從計算導出的結果，打從一開始有沒有感情的成分。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"흐음, 정말 그렇게 생각하니?","JPN":"ふーん、本当にそう思ってるのかしら。","ENG":"Hmm... Do you truly believe that?","TWN":"呵呵，你當真那麼認為？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"글쎄. 지금은 계산할 수 없군.","JPN":"どうだろう。今は計算できない。","ENG":"I do not know. It cannot be computed as of right now.","TWN":"不知道，我現在無法計算。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};